bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Start a transaction
    db.execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds
    auto check_query = db.prepare("SELECT balance FROM Account WHERE account_id = ?");
    check_query.bind(1, from_account_id);
    auto result = check_query.execute();

    if (!result.next()) {
      db.execute("ROLLBACK");
      return false; // Account doesn't exist
    }

    double from_balance = result.get<double>(0);
    if (from_balance < amount) {
      db.execute("ROLLBACK");
      return false; // Insufficient funds
    }

    // Update sender account (deduct amount)
    auto update_from = db.prepare("UPDATE Account SET balance = balance - ? WHERE account_id = ?");
    update_from.bind(1, amount);
    update_from.bind(2, from_account_id);
    update_from.execute();

    // Update receiver account (add amount)
    auto update_to = db.prepare("UPDATE Account SET balance = balance + ? WHERE account_id = ?");
    update_to.bind(1, amount);
    update_to.bind(2, to_account_id);
    update_to.execute();

    // Commit the transaction
    db.execute("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // Handle any database errors
    return false;
  }
}
```

After verifying the sender's account exists and has sufficient balance, I deduct from the source and add to the destination account. The transaction commits if both updates succeed, otherwise the exception handler catches any errors and rolls back implicitly. I need to reconsider the approach based on the SQL pattern provided. The key insight is using `WHERE account_id = ? AND balance >= ?` to atomically verify sufficient funds—if this UPDATE affects zero rows, either the account doesn't exist or there's insufficient balance.

Let me refactor the implementation to follow this pattern more directly:

```cpp
bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    db.execute("BEGIN TRANSACTION");

    // Deduct from sender with balance check
    auto deduct = db.prepare("UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?");
    deduct.bind(1, amount);
    deduct.bind(2, from_account_id);
    deduct.bind(3, amount);
    auto deduct_result = deduct.execute();

    if (deduct_result.rows_affected() == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Add to receiver
    auto add = db.prepare("UPDATE Account SET balance = balance + ? WHERE account_id = ?");
    add.bind(1, amount);
    add.bind(2, to_account_id);
    auto add_result = add.execute();

    if (add_result.rows_affected() == 0) {
