    try {
      // Update sender account (deduct amount) with balance check
      // This ensures atomically that the account exists AND has sufficient funds
      auto stmt_from = db.prepare(
        "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?"
      );
      stmt_from.bind(1, amount);
      stmt_from.bind(2, from_account_id);
      stmt_from.bind(3, amount);
      stmt_from.execute();

      // Check if the update affected any rows
      if (db.changes() == 0) {
        // Either account doesn't exist or insufficient funds
        db.execute("ROLLBACK");
        return false;
      }

      // Update receiver account (add amount)
      auto stmt_to = db.prepare(
        "UPDATE Account SET balance = balance + ? WHERE account_id = ?"
      );
      stmt_to.bind(1, amount);
      stmt_to.bind(2, to_account_id);
      stmt_to.execute();

      // Check if receiver account exists
      if (db.changes() == 0) {
        // Receiver account doesn't exist
        db.execute("ROLLBACK");
        return false;
      }

      // Commit the transaction
      db.execute("COMMIT");
      return true;

    } catch (...) {
      // Rollback on any exception during transaction
      db.execute("ROLLBACK");
      return false;
    }

  } catch (...) {
    // Failed to connect or other error
    return false;
  }
}

}  // namespace transaction_transfer_funds

