 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  std::vector<DepProj> results;

  // Note: SQLite doesn't natively support RIGHT JOIN
  // To simulate "Department RIGHT JOIN Project" (include all departments),
  // we use "Department LEFT JOIN Project"
  // However, based on the struct definition with optional department_name
  // and required project_name, we interpret this as including all projects
  // So we actually perform: Project LEFT JOIN Department
  auto query = conn.execute(
    "SELECT d.name, p.name "
    "FROM Project p "
    "LEFT JOIN Department d ON p.department_id = d.department_id"
  );

  // Process query results
  for (const auto& row : query) {
    DepProj dp;

    // Department name is optional (may be NULL if project has no matching department)
    if (row.is_null(0)) {
      dp.department_name = std::nullopt;
    } else {
      dp.department_name = row.get<std::string>(0);
    }

    // Project name is required
    dp.project_name = row.get<std::string>(1);

    results.push_back(dp);
  }

  return results;
}

}  // namespace right_join_departments_projects
