    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )");

  auto count_results = friend_count_query.execute();
  while (count_results.next()) {
    int user_id = count_results.get<int>(0);
    std::string username = count_results.get<std::string>(1);
    int count = count_results.get<int>(2);
    std::cout << username << " (ID: " << user_id << ") has " << count << " friend(s)" << std::endl;
  }

  // Query 5: Find users in same city who are not yet friends (recommendation)
  std::cout << "\n=== Query 5: Friend Recommendations (Same City, Not Friends) ===" << std::endl;
  auto recommendation_query = db.prepare(R"(
    SELECT u1.username, u2.username, u1.city
    FROM User u1
    INNER JOIN User u2 ON u1.city = u2.city
    WHERE u1.user_id < u2.user_id
      AND u1.city IS NOT NULL
      AND u1.city != ''
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
  )");

  auto rec_results = recommendation_query.execute();
  while (rec_results.next()) {
    std::string user1 = rec_results.get<std::string>(0);
    std::string user2 = rec_results.get<std::string>(1);
    std::string city = rec_results.get<std::string>(2);
    std::cout << "Recommend " << user1 << " to " << user2 << " (both in " << city << ")" << std::endl;
  }

  // Return all friend connections as FriendConnection vector
  std::vector<FriendConnection> result;
  auto all_friends_query = db.prepare(R"(
    SELECT u1.username, u2.username
    FROM Friendship f
    INNER JOIN User u1 ON f.user_id1 = u1.user_id
    INNER JOIN User u2 ON f.user_id2 = u2.user_id
    ORDER BY u1.username, u2.username
  )");

  auto all_results = all_friends_query.execute();
  while (all_results.next()) {
    FriendConnection conn;
    conn.user1_name = all_results.get<std::string>(0);
    conn.user2_name = all_results.get<std::string>(1);
    result.push_back(conn);
  }

  return result;
}

