  for (const auto& dept : depts) {
    dept_table.insert(dept);
  }

  // Insert employees
  for (const auto& emp : emps) {
    emp_table.insert(emp);
  }

  JoinAnalysis analysis;

  // INNER JOIN: Get employees with assigned departments
  analysis.inner_join_results = db.query<JoinResult>(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "INNER JOIN Employee e ON d.department_id = e.department_id"
  );

  // LEFT JOIN: Include all employees (even without departments)
  analysis.left_join_results = db.query<JoinResult>(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id"
  );

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so we simulate it with LEFT JOIN (reversed tables)
  analysis.right_join_results = db.query<JoinResult>(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "LEFT JOIN Employee e ON d.department_id = e.department_id"
  );

  // FULL OUTER JOIN: Include all employees and departments
  // SQLite doesn't support FULL OUTER JOIN, so we simulate it with UNION
  analysis.full_join_results = db.query<JoinResult>(
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id "
    "UNION "
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "LEFT JOIN Employee e ON d.department_id = e.department_id "
    "WHERE e.employee_id IS NULL"
  );

  return analysis;
}

}  // namespace analyze_department_employees

